-- Insert form field values for all leads
-- We need to get the lead IDs after insertion, so we'll use a CTE approach
-- EDT504 leads form fields
INSERT INTO public.lead_form_field_values (lead_id, field_name, field_label, field_value)
SELECT l.id, f.field_name, f.field_label, f.field_value
FROM leads l
CROSS JOIN (VALUES
  ('qual_o_valor_disponível_para_entrada?', 'Qual o valor disponível para entrada?', null::text),
  ('quando_pretende_comprar?', 'Quando pretende comprar?', null::text),
  ('qual_é_o_seu_principal_objetivo?', 'Qual é o seu principal objetivo?', null::text)
) AS f(field_name, field_label, field_value)
WHERE l.meta_lead_id = 'l:931585319539935'
AND NOT EXISTS (SELECT 1 FROM lead_form_field_values lfv WHERE lfv.lead_id = l.id AND lfv.field_name = f.field_name);

-- Update field values per lead
UPDATE lead_form_field_values SET field_value = 'até r$ 30 mil' WHERE lead_id = (SELECT id FROM leads WHERE meta_lead_id = 'l:931585319539935') AND field_name = 'qual_o_valor_disponível_para_entrada?';
UPDATE lead_form_field_values SET field_value = 'nos próximos 3 meses' WHERE lead_id = (SELECT id FROM leads WHERE meta_lead_id = 'l:931585319539935') AND field_name = 'quando_pretende_comprar?';
UPDATE lead_form_field_values SET field_value = 'comprar' WHERE lead_id = (SELECT id FROM leads WHERE meta_lead_id = 'l:931585319539935') AND field_name = 'qual_é_o_seu_principal_objetivo?';
